/// # Example
#[napi(js_name = "encodeDataUrl")]
pub fn encode_data_url(bytes: napi::bindgen_prelude::Buffer, mime: Option<String>) -> String {
    let bytes: Vec<u8> = bytes.to_vec();
    liter_llm::image::encode_data_url(&bytes, mime.as_deref())
}

/// Decode a base64 data URL into `DecodedDataUrl`.
