/// Count tokens in a text string using the tokenizer for the given model.
///
/// The tokenizer is resolved from the model name prefix (e.g. `"gpt-4o"` maps
/// to the `Xenova/gpt-4o` HuggingFace tokenizer). Tokenizers are cached after
/// first load.
///
/// # Errors
///
/// Returns `LiterLlmError.BadRequest` if the tokenizer cannot be loaded
/// (e.g. network failure on first use) or if tokenization itself fails.
#[allow(clippy::missing_errors_doc)]
#[napi(js_name = "countTokens")]
pub fn count_tokens(model: String, text: String) -> Result<i64> {
    liter_llm::count_tokens(&model, &text)
        .map(|val| val as i64)
        .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))
}

/// Count tokens for a full `ChatCompletionRequest`.
///
/// Sums tokens across all message text contents plus a per-message overhead
/// of ~4 tokens (for role, separators, and formatting metadata). Tool
/// definitions and multimodal content parts (images, audio, documents) are
/// not counted — only textual content contributes to the token total.
///
/// # Errors
///
/// Returns `LiterLlmError.BadRequest` if the tokenizer cannot be loaded or
/// if tokenization fails for any message.
#[allow(clippy::missing_errors_doc)]
#[napi(js_name = "countRequestTokens")]
pub fn count_request_tokens(model: String, req: Option<JsChatCompletionRequest>) -> Result<i64> {
    let req_core: liter_llm::ChatCompletionRequest = req.unwrap_or_default().into();

    liter_llm::count_request_tokens(&model, &req_core)
        .map(|val| val as i64)
        .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))
}

/// Assert that `current_len + incoming` does not exceed `limit`.
///
/// Call this before appending `incoming` bytes to any buffer that must
/// stay below `limit`.  Returns `Err(LiterLlmError.Streaming)` on overflow
/// and emits a `tracing.warn!` with context.
///
/// # Example
#[allow(clippy::missing_errors_doc)]
#[napi(js_name = "checkBound")]
pub fn check_bound(context: String, current_len: i64, incoming: i64, limit: i64) -> Result<()> {
    liter_llm::util::bounds::check_bound(&context, current_len as usize, incoming as usize, limit as usize)
        .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))
}

#[cfg(any(
    all(feature = "native-http", not(target_os = "windows")),
    all(feature = "native-http", target_os = "windows")
))]
/// Install the `ring` crypto provider as the rustls process default, idempotently.
///
/// rustls 0.23+ removed the implicit default provider. This function installs
/// `ring` once per process. Subsequent calls are no-ops. Calling it after
/// another rustls crypto provider has already been installed is safe: the
/// `Err` from `install_default()` is silently ignored.
///
/// Called automatically by every internal `reqwest.Client` constructor
/// (auth providers, default HTTP client). Bindings and downstream consumers
/// reach those constructors transitively, so no manual init is required.
///
/// WASM builds are exempt — the WASM target uses the browser/Node.js fetch
/// API instead of rustls, so no crypto provider is needed.
///
/// Windows builds use native-tls (SChannel) via reqwest, so rustls is not
/// present and no crypto provider installation is needed.
#[napi(js_name = "ensureCryptoProvider")]
pub fn ensure_crypto_provider() -> () {
    liter_llm::ensure_crypto_provider()
}

#[allow(clippy::missing_errors_doc)]
#[napi(js_name = "chatStream")]
pub async fn chat_stream(engine: &JsDefaultClient, model: String) -> Result<ChatStreamIterator> {
    let core_chat_completion_request: liter_llm::ChatCompletionRequest = JsChatCompletionRequest {
        model: Some(model),
        ..Default::default()
    }
    .into();
    let inner = engine.inner.clone();
    let (tx, rx) = tokio::sync::mpsc::channel(32);
    tokio::spawn(async move {
        use futures_util::StreamExt;
        match inner.chat_stream(core_chat_completion_request).await {
            Err(e) => {
                let _ = tx
                    .send(Err(napi::Error::new(napi::Status::GenericFailure, e.to_string())))
                    .await;
            }
            Ok(mut stream) => {
                while let Some(chunk) = stream.next().await {
                    let item = match chunk {
                        Ok(c) => JsChatCompletionChunk::from(c),
                        Err(e) => {
                            let _ = tx
                                .send(Err(napi::Error::new(napi::Status::GenericFailure, e.to_string())))
                                .await;
                            break;
                        }
                    };
                    if tx.send(Ok(item)).await.is_err() {
                        break;
                    }
                }
            }
        }
    });
    let iter = ChatStreamIterator {
        receiver: Arc::new(tokio::sync::Mutex::new(rx)),
    };
    Ok(iter)
}

