impl From<JsMessage> for liter_llm::types::Message {
    fn from(val: JsMessage) -> Self {
        match val.role_tag.as_str() {
            "system" => Self::System(val.system.map(|v| v.into()).unwrap_or_default()),
            "user" => Self::User(val.user.map(|v| v.into()).unwrap_or_default()),
            "assistant" => Self::Assistant(val.assistant.map(|v| v.into()).unwrap_or_default()),
            "tool" => Self::Tool(val.tool.map(|v| v.into()).unwrap_or_default()),
            "developer" => Self::Developer(val.developer.map(|v| v.into()).unwrap_or_default()),
            "function" => Self::Function(val.function.map(|v| v.into()).unwrap_or_default()),
            _ => Self::System(Default::default()),
        }
    }
}

